%[text] # `Compare: Uninterrupted, Segmented, & Independent Traces:`
%%
%[text] ## `Configure MATLAB:`
restoredefaultpath;    clear;    close all;    clc;    addpath(genpath(fileparts(mfilename('fullpath')))) % In case "Configure" is not available.
Configure
%%
%[text] ## `Generate Data:`
%[text] ### `Set HMM(2) Parameters:` $\\mathbf{\\vartheta}\\equiv\\{\\pi\_{\\sigma\_{1}\\to\\sigma\_{2}},\\pi\_{\\sigma\_{2}\\to\\sigma\_{1}}\\}\\sim\\mathbb{B}(1,1)\_$
GT.p = betarnd(1,1); % Probability(σ1 -> σ2)
GT.q = betarnd(1,1); % Probability(σ2 -> σ1)
%[text]  `Transition Matrix` $\\mathbf{\\Pi}\n\\equiv\\{\\mathbf{\\pi}\_{\\sigma\_{m}}\\}\n\\equiv\\{\\pi\_{\\sigma\_{m}\\to\\sigma\_{m^{\\prime}}}\\}\n\\in\[0,1\]^{M \\times M}$`:`
GT.TransitionMatrix       = [1-GT.p, GT.p; GT.q, 1-GT.q];
%[text]  `Stationary Distribution` $\\mathbf{\\varrho}=\\mathbf{\\varrho}\\mathbf{\\Pi}$`:` 
GT.StationaryDistribution = [GT.q, GT.p] / (GT.p + GT.q);
%[text] ####  `Emission Model` $\\mathbb{P}(w\_{n}\\,|\\,s\_{n},\\phi\_{s\_{n}})$`:`
GT.Mean              = [1  2]           ;
GT.Variance          = 0.005            ;
GT.StandardDeviation = sqrt(GT.Variance);

EmissionModel = @(w,S) pdfNormal(w, GT.Mean(S), GT.Variance);
%[text] ### `Set Data Acquisition Parameters:`
Long.nTimes = 10000                  ;
nSegments   = Long.nTimes / 125      ;
Many.nTimes = Long.nTimes / nSegments;
%[text] ### `Simulation:`
%[text] ####  `Initialize:`
Long.S = zeros(Long.nTimes,1);
Long.w = zeros(Long.nTimes,1);
Many.S = cell(nSegments,1)   ;
Many.w = cell(nSegments,1)   ;
Rest.S = cell(nSegments,1)   ;
Rest.w = cell(nSegments,1)   ;
%[text] #### `Uninterrupted Trace:` $\\mathbf{\\mathit{w}}$
[Long.S, Long.w] = simulateHMM(Long.nTimes, GT.StationaryDistribution, GT.TransitionMatrix, GT.Mean, GT.StandardDeviation);
for  nSegment  = 1 :       nSegments
  if nSegment == 1 ; Times{nSegment} = 1 : Many.nTimes                           ;
  else             ; Times{nSegment} = Times{nSegment-1}(end) + (1 : Many.nTimes);
  end
%[text] #### `Segmented Traces:` $\\widetilde{\\mathbf{{w}}$
    Rest.S{nSegment} = Long.S(Times{nSegment});
    Rest.w{nSegment} = Long.w(Times{nSegment});
%[text] #### `Many Genuinely Independent, Short Traces:` $\\mathbf{{u}$
    [Many.S{nSegment}, Many.w{nSegment}] = simulateHMM(Many.nTimes, GT.StationaryDistribution, GT.TransitionMatrix, GT.Mean, GT.StandardDeviation);
end
%%
%[text] ## `Analyze Data:`
%[text] ####  Parameter `Grid:`
epsilon  = 10^(-4)    ;
gridMin  = 0 + epsilon;
gridMax  = 1 - epsilon;

nLattice = 1000                                ;
Grid.p   = linspace(gridMin, gridMax, nLattice);
Grid.q   = linspace(gridMin, gridMax, nLattice);
%[text] ####  `Precompute Emissions:`
nStates = length(GT.Mean)                                  ;
BLong   = getEmissionMatrix(Long.w, EmissionModel, nStates);
BMany   = cell(nSegments,1)                                ;
for nSegment = 1 : nSegments, BMany{nSegment} = getEmissionMatrix(Many.w{nSegment}, EmissionModel, nStates);    end
BRest  = cell(nSegments,1);
for nSegment = 1 : nSegments, BRest{nSegment} = getEmissionMatrix(Rest.w{nSegment}, EmissionModel, nStates);    end
%[text] ###  Marginal Posterior`:`
ZERO                        = zeros(numel(Grid.p), numel(Grid.q));
Long.logLikelihood          = ZERO;
Long.logLikelihoodRestarted = ZERO;
Many.logLikelihood          = ZERO;
Rest.logLikelihood          = ZERO;

useParallel = ~isempty(ver("Parallel"));
if useParallel
    Pool = gcp("NoCreate");
    if isempty(Pool), parpool; end
end

startSegment = 1 : Many.nTimes : Long.nTimes;
endSegment   = startSegment + Many.nTimes - 1;

longLogL        = ZERO;
LL_long_restart = ZERO;
LL_many         = ZERO;
LL_rest         = ZERO;

if useParallel
    pGrid           = Grid.p;
    qGrid           = Grid.q;
    BLong_local     = BLong;
    BMany_local     = BMany;
    BRest_local     = BRest;
    segStarts_local = startSegment;
    segEnds_local   = endSegment;

    parfor pIndex = 1:numel(pGrid)
           p      = pGrid(pIndex);

        rowL        = zeros(1, numel(qGrid));
        rowLrestart = zeros(1, numel(qGrid));
        rowM        = zeros(1, numel(qGrid));
        rowR        = zeros(1, numel(qGrid));

        for qIndex = 1:numel(qGrid)
            q      = qGrid(qIndex);

            TransitionMatrix       = [1-p, p; q, 1-q];
            StationaryDistribution = [q, p] / (p + q);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{\\mathit{w}},\\mathbf{\\phi})$ `(Parallel)`
            rowL(qIndex) = getMarginalLikelihood(BLong_local, StationaryDistribution, TransitionMatrix);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\widetilde{\\mathbf{w}},\\mathbf{\\phi})$ `(Parallel)`
            rowLrestart(qIndex) = getStationaryMarginalLikelihood(BLong_local, segStarts_local, segEnds_local, StationaryDistribution, TransitionMatrix);
            % Explicitly Partitioned (for Diagnostics)
            rowR(qIndex) = getStationaryMarginalLikelihoodCELL(BRest_local, StationaryDistribution, TransitionMatrix);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{{u},\\mathbf{\\phi})$ `(Parallel)`
            rowM(qIndex) = getStationaryMarginalLikelihoodCELL(BMany_local, StationaryDistribution, TransitionMatrix);
        end

        longLogL(pIndex,:)        = rowL;
        LL_long_restart(pIndex,:) = rowLrestart;
        LL_many(pIndex,:)         = rowM;
        LL_rest(pIndex,:)         = rowR;

    end
else
    for pIndex = 1:numel(Grid.p)
        p = Grid.p(pIndex);

        for qIndex = 1:numel(Grid.q)
            q = Grid.q(qIndex);

            TransitionMatrix       = [1-p, p; q, 1-q];
            StationaryDistribution = [q, p] / (p + q);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{\\mathit{w}},\\mathbf{\\phi})$
            longLogL(pIndex,qIndex) = getMarginalLikelihood(BLong, StationaryDistribution, TransitionMatrix);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\widetilde{\\mathbf{w}},\\mathbf{\\phi})$
            LL_long_restart(pIndex,qIndex) = getStationaryMarginalLikelihood(BLong, startSegment, endSegment, StationaryDistribution, TransitionMatrix);
            % Explicitly Partitioned (for Diagnostics)
            LL_rest(pIndex,qIndex) = getStationaryMarginalLikelihoodCELL(BRest, StationaryDistribution, TransitionMatrix);
%[text] #### $\\mathbb{P}(\\mathbf{\\vartheta} \\,|\\, \\mathbf{{u},\\mathbf{\\phi})$
            LL_many(pIndex,qIndex) = getStationaryMarginalLikelihoodCELL(BMany, StationaryDistribution, TransitionMatrix);
        end
    end
end

Long.logLikelihood          = longLogL;
Long.logLikelihoodRestarted = LL_long_restart;
Many.logLikelihood          = LL_many;
Rest.logLikelihood          = LL_rest;
%[text] #### `Prior` $\\mathbb{P}(\\mathbf{\\vartheta})$`:` $\\mathbb{B}(1,1)$ `(Uniform).`
Shapes    = [1  1];

logPriorP = (Shapes(1)-1)*log(Grid.p) + (Shapes(2)-1)*log1p(-Grid.p) - betaln(Shapes(1),Shapes(2));
logPriorQ = (Shapes(1)-1)*log(Grid.q) + (Shapes(2)-1)*log1p(-Grid.q) - betaln(Shapes(1),Shapes(2));

Prior.p   = betapdf(Grid.p, Shapes(1), Shapes(2));  Prior.p = Prior.p / trapz(Grid.p, Prior.p);
Prior.q   = betapdf(Grid.q, Shapes(1), Shapes(2));  Prior.q = Prior.q / trapz(Grid.q, Prior.q);
%[text] #### `Joint Posterior` $\\mathbb{P}(\\mathbf{\\vartheta}\\,|\\,\\mathbf{\\mathit{w}})$`:`
logPostLongRaw = Long.logLikelihood + logPriorP.' + logPriorQ;
logPostLongRestartRaw = Long.logLikelihoodRestarted + logPriorP.' + logPriorQ;
logPostManyRaw = Many.logLikelihood + logPriorP.' + logPriorQ;
logPostRest    = Rest.logLikelihood + logPriorP.' + logPriorQ;
%[text] #### `Marginal Posteriors:`
[postLong, ~]        = normalizeLog2D(logPostLongRaw, Grid.p, Grid.q)       ;
[postLongRestart, ~] = normalizeLog2D(logPostLongRestartRaw, Grid.p, Grid.q);
[postMany, ~]        = normalizeLog2D(logPostManyRaw, Grid.p, Grid.q)       ;
[postRest, ~]        = normalizeLog2D(logPostRest, Grid.p, Grid.q)          ;
%[text] ### `Kullback-Leibler Divergence (Information Gain):` $\\int{\\mathrm{d}\\bf{\\vartheta}}\\:\n\\left\[\n{\\mathbb{P}(\\bf{\\vartheta}\\,|\\,\\bf{\\it{w}})}\n\\times\n\\log\_{2}\n\\frac{\\mathbb{P}(\\bf{\\vartheta}\\,|\\,\\bf{\\it{w}})}\n{\\mathbb{P}(\\bf{\\vartheta})}\n\\right\]$.
Prior.joint = Prior.p(:) * Prior.q(:).';

Info.Long.bits        = KullbackLeiblerDivergence(postLong,        Prior.joint, Grid.p, Grid.q);
Info.Many.bits        = KullbackLeiblerDivergence(postMany,        Prior.joint, Grid.p, Grid.q);
Info.LongRestart.bits = KullbackLeiblerDivergence(postLongRestart, Prior.joint, Grid.p, Grid.q);
Info.Restart.bits     = KullbackLeiblerDivergence(postRest,        Prior.joint, Grid.p, Grid.q);

Info.Long.bitsPerObservation        = Info.Long.bits        / Long.nTimes;
Info.Many.bitsPerObservation        = Info.Many.bits        / Long.nTimes;
Info.LongRestart.bitsPerObservation = Info.LongRestart.bits / Long.nTimes;
Info.Restart.bitsPerObservation     = Info.Restart.bits     / Long.nTimes;

dt = 1;   % Time per Frame;

Info.Long.bitsPerTime        = Info.Long.bits        / (Long.nTimes * dt);
Info.Many.bitsPerTime        = Info.Many.bits        / (Long.nTimes * dt);
Info.LongRestart.bitsPerTime = Info.LongRestart.bits / (Long.nTimes * dt);
Info.Restart.bitsPerTime     = Info.Restart.bits     / (Long.nTimes * dt);
%[text] ### Jensen-Shannon Divergence:
% "Same information?" ==> compare the posterior surfaces directly through Jensen-Shannon (JS) Divergence:
Info.JS.Long_vs_Many.bits          = JensenShannonDivergence(postLong,        postMany, Grid.p, Grid.q);
Info.JS.LongRestart_vs_Many.bits   = JensenShannonDivergence(postLongRestart, postMany, Grid.p, Grid.q);
Info.JS.Long_vs_LongRestart.bits   = JensenShannonDivergence(postLong,        postLongRestart, Grid.p, Grid.q);

Info.JS.Long_vs_Restart.bits         = JensenShannonDivergence(postLong,        postRest, Grid.p, Grid.q);
Info.JS.Restart_vs_LongRestart.bits  = JensenShannonDivergence(postRest,        postLongRestart, Grid.p, Grid.q);
Info.JS.Many_vs_Restart.bits         = JensenShannonDivergence(postMany,        postRest, Grid.p, Grid.q);
%[text] ####   Numerical `Normalization:`
Long.logPosterior.p = trapz(Grid.q, postLong, 2)';  
Long.logPosterior.p = Long.logPosterior.p / trapz(Grid.p, Long.logPosterior.p);
Long.logPosterior.q = trapz(Grid.p, postLong, 1);   
Long.logPosterior.q = Long.logPosterior.q / trapz(Grid.q, Long.logPosterior.q);

Long.logPosteriorRestarted.p = trapz(Grid.q, postLongRestart, 2)';  
Long.logPosteriorRestarted.p = Long.logPosteriorRestarted.p / trapz(Grid.p, Long.logPosteriorRestarted.p);
Long.logPosteriorRestarted.q = trapz(Grid.p, postLongRestart, 1);   
Long.logPosteriorRestarted.q = Long.logPosteriorRestarted.q / trapz(Grid.q, Long.logPosteriorRestarted.q);

Many.logPosterior.p = trapz(Grid.q, postMany, 2)';  
Many.logPosterior.p = Many.logPosterior.p / trapz(Grid.p, Many.logPosterior.p);
Many.logPosterior.q = trapz(Grid.p, postMany, 1);   
Many.logPosterior.q = Many.logPosterior.q / trapz(Grid.q, Many.logPosterior.q);

Rest.logPosterior.p = trapz(Grid.q, postRest, 2)';  
Rest.logPosterior.p = Rest.logPosterior.p / trapz(Grid.p, Rest.logPosterior.p);
Rest.logPosterior.q = trapz(Grid.p, postRest, 1);   
Rest.logPosterior.q = Rest.logPosterior.q / trapz(Grid.q, Rest.logPosterior.q);
%[text] ### Summary Statistics:
Summary.Long.p = summarizePosterior(Grid.p, Long.logPosterior.p);
Summary.Long.q = summarizePosterior(Grid.q, Long.logPosterior.q);

Summary.LongRestart.p = summarizePosterior(Grid.p, Long.logPosteriorRestarted.p);
Summary.LongRestart.q = summarizePosterior(Grid.q, Long.logPosteriorRestarted.q);

Summary.Many.p = summarizePosterior(Grid.p, Many.logPosterior.p);
Summary.Many.q = summarizePosterior(Grid.q, Many.logPosterior.q);

Summary.Rest.p = summarizePosterior(Grid.p, Rest.logPosterior.p);
Summary.Rest.q = summarizePosterior(Grid.q, Rest.logPosterior.q);

save("Data(Figure=2,Seed="+Pseudorandom.Seed+",nSegments="+nSegments+").mat")
%%
%[text] ## `Visualize Data:`
%[text] ### Loading  Trace Data:
%{
Configure
Pseudorandom.Seed =  22; %[control:slider:906c]{"position":[22,24]}
Seed = Pseudorandom.Seed;
nSegments      = ...%125; %[control:dropdown:8692]{"position":[22,25]}
                 400;
DataFolder = "C:\Users\zacha\ASU Dropbox\Zachary Hendrix\Likelihood Preservation\";
load(DataFolder + "Data(Figure=1,Seed="+Pseudorandom.Seed+",nSegments="+nSegments+").mat")
Pseudorandom.Seed = Seed;
%}
%[text] ### `Graphical Parameters:`
showTrajectory = true; %[control:checkbox:3f45]{"position":[18,22]}
Color.Path  = [0.502 0.502 0.502]; %[control:colorPicker:851c]{"position":[15,34]}
Color.Long  = [0.780 0.039 0.039]; %[control:colorPicker:21d1]{"position":[15,34]}
Color.Rest  = [0.961 0.467 0.161]; %[control:colorPicker:3026]{"position":[15,34]}
Color.Many  = [0.929 0.694 0.125]; %[control:colorPicker:274f]{"position":[15,34]}
Color.Prior = [0.067 0.443 0.745]; %[control:colorPicker:3b9a]{"position":[15,34]}
Color.True  = [0.231 0.667 0.196]; %[control:colorPicker:8a85]{"position":[15,34]}
MarkerSize  =  6    ;
FontSize    = 16    ;
LineWidth   =  2    ;
StairWidth  =  1    ;
StairStyle  = "-"   ;
yTicks      = [1  2];

Units.Time = "ks"   ;


if Pseudorandom.Seed == 22;    XLim = [1/8    1/4];
else                      ;    XLim = [ 0      1 ]; % Generic; Distributions will likely overlap at this scale.
end

if nSegments < 4;    Showing = 2;    zoomSamples = Showing * Many.nTimes;    Start = 1              ;    End = Long.nTimes            ;
else;                Showing = 4;    zoomSamples = Showing * Many.nTimes;    Start = Long.nTimes / 2;    End = Start + zoomSamples - 1;
end

zoomTimes   = Start : End;
%[text] ###  `Initialize:`
close    all
Figure = figure("Name",'Figure(2)', "Position",[80 80 1280 880]);
if nSegments < 4;    Tiles  = tiledlayout(Figure, 5, Showing, "TileSpacing",'Tight', "Padding",'Compact');
else            ;    Tiles  = tiledlayout(Figure, 6, Showing, "TileSpacing",'Tight', "Padding",'Compact');
end
%[text] ###  `Long Trajectory` $(\\mathbf{\\mathit{w}})$`:`
longAxes = nexttile(Tiles, [1  Showing]);    hold(longAxes,"On")

longAxes.FontSize = FontSize;

xline(longAxes, Start, '--', 'Color', zoomColor, "LineWidth",2);
xline(longAxes, End,   '--', 'Color', zoomColor, "LineWidth",2);

longScatter = scatter(longAxes, 0:Long.nTimes-1, Long.w, MarkerSize, 'o', "MarkerEdgeColor", Color.Long, "MarkerFaceColor",Color.Long, "DisplayName",'Measurement');
if showTrajectory;    stairs (longAxes, 0:Long.nTimes-1, Long.S, "Color",Color.Path, "LineWidth",StairWidth, "DisplayName",'State', "LineStyle",StairStyle);    end
% PRETEND GRAPH FOR LEGEND %
longStairs =    stairs (longAxes, [-inf,-inf], [+inf,+inf], "Color",Color.Path, "LineWidth",StairWidth, "DisplayName",'GT Path', "LineStyle",StairStyle);

ylabel(longAxes,"Signal:  $\mathbf{\mathit{w}}$", "Interpreter",'LaTeX');
  ylim(longAxes, [min(Long.w(:))  max(Long.w(:))]);
yticks(longAxes, yTicks)
longAxes.YAxis(1).Color             = "k"     ;
longAxes.XLim  = [0  Long.nTimes];
longAxes.XTick = linspace(longAxes.XLim(1), longAxes.XLim(2), 5);
if Units.Time == "ks"
  longAxes.XTickLabel  = {round(longAxes.XTick / 10^(3), 2)};
  longAxes.XTickLabel(floor(end/2)+1) = {"$t \: \mathrm{[10^{3} \cdot s]}$"};
else
  longAxes.XTickLabel = {longAxes.XTick};
  longAxes.XTickLabel(floor(end/2)+1) = {"Time: $t \: \mathrm{[s]}$"};
end

wLegend = legend(longAxes, [longScatter, longStairs], "Box",'Off', "AutoUpdate",'Off', "Orientation",'Horizontal');
grid(longAxes, "Off");

wLegend.FontSize = FontSize - 2             ;

longAxes.XAxisLocation = "Top";

Leg0 = wLegend.Position                     ;
wLegend.Position = Leg0 + [-0.0265,0.03,0,0];
Leg0            = wLegend.Position          ;
%[text] ##  `Long Trajectory Zoomed In` $(w\_{x:y})$`:`
zoomColor = [0  0  0];
if nSegments > 4
  zoomAxes = nexttile(Tiles, [1  Showing]); hold(zoomAxes,"On");
  
  scatter(zoomAxes, zoomTimes, Long.w(zoomTimes), MarkerSize, 'o', "MarkerEdgeColor", Color.Long, "MarkerFaceColor", Color.Long, "DisplayName",'Raw');
  if showTrajectory
     stairs(zoomAxes, zoomTimes, Long.S(zoomTimes), "Color",Color.Path, "LineWidth",StairWidth, "DisplayName",'GT Path', "LineStyle",StairStyle);
  end
  
  ylabel(zoomAxes,"$\mathbf{\mathit{w}}$","Interpreter",'LaTeX');
  ylim(zoomAxes, [min(Long.w(zoomTimes))  max(Long.w(zoomTimes))]);
  yticks(longAxes, yTicks)
  xlim(zoomAxes, [zoomTimes(1)  zoomTimes(end)]);

  grid(zoomAxes, "Off");
  
if Units.Time == "ks"
  zoomAxes.XTickLabel  = {round(zoomAxes.XTick / 10^(3), 2)};
  zoomAxes.XTickLabel(floor(end/2)+1) = {"$t \: \mathrm{[10^{3} \cdot s]}$"};
else
  zoomAxes.XTickLabel = {zoomAxes.XTick};
  zoomAxes.XTickLabel(floor(end/2)+1) = {"Time: $t \: \mathrm{[s]}$"};
end


  drawnow;
  zoomWidth = 2;
  drawZoomConnectors(Figure, longAxes, zoomAxes, Start, End, zoomColor, zoomWidth);
end

zoomAxes.XLim   = [Start    End];
zoomAxes.XTick  = linspace(zoomAxes.XLim(1), zoomAxes.XLim(2), 5) ;
zoomAxes.XTickLabel                 = {round(zoomAxes.XTick / 10^(3), 2)};
zoomAxes.XTickLabel(floor(end/2)+1) = {"$t \: \mathrm{[10^{3} \cdot s]}$"};
zoomAxes.FontSize                   = FontSize;

zoomAxes.YTick = yTicks;
%[text] ## `Segmented Trajectory:`
  restAxes = nexttile(Tiles, [1  Showing]); hold(restAxes,"On");
  restAxes.FontSize = FontSize;
  scatter(restAxes, zoomTimes, Long.w(zoomTimes), MarkerSize, 'o', "MarkerEdgeColor", Color.Rest, "MarkerFaceColor", Color.Rest, "DisplayName",'Raw');

  ylabel(restAxes,"$\widetilde{\mathbf{w}}$","Interpreter",'LaTeX');

  ylim(restAxes, [min(Long.w(zoomTimes))  max(Long.w(zoomTimes))]);
  yticks(restAxes, yTicks)
  xlim(restAxes, [zoomTimes(1)  zoomTimes(end)]);
  grid(restAxes, "Off");
  
if Units.Time == "ks"
  restAxes.XTickLabel  = {round(restAxes.XTick / 10^(3), 2)};
  restAxes.XTickLabel(floor(end/2)+1) = {"$t \: \mathrm{[10^{3} \cdot s]}$"};
else
  restAxes.XTickLabel = {restAxes.XTick};
  restAxes.XTickLabel(floor(end/2)+1) = {"Time: $t \: \mathrm{[s]}$"};
end

segLeft  = 0 : Many.nTimes : Long.nTimes-1;
segRight = segLeft + Many.nTimes - 1;
useSeg   = find(segRight >= Start & segLeft <= End);

for idx     = 1:numel(useSeg)
    s       = useSeg(idx)         ;
    left    = segLeft(s)          ;
    right   = segRight(s)         ;
    t0      = max(Start, left)    ; 
    t1      = min(End, right)     ;
    tGlobal = t0 : t1             ;
    iLocal  = (tGlobal - left) + 1;

    if idx ~= numel(useSeg);    text(restAxes, mean([t1-1,t1]), mean(restAxes.YLim), "$+$", "Color",'k', "FontSize",FontSize+2);    end

    if showTrajectory;    stairs(restAxes, tGlobal, Long.S(tGlobal), "Color",Color.Path, "LineWidth",StairWidth, "DisplayName",'GT', "LineStyle",StairStyle);    end
end

restAxes.XTick      = zoomAxes.XTick     ;
restAxes.XTickLabel = zoomAxes.XTickLabel;
restAxes.YTick      = yTicks             ;
restAxes.YTickLabel = zoomAxes.YTickLabel;
%[text] ###  `Probability:`
distributionAxes(1) = nexttile(Tiles, [1 ceil(Showing/2)]); 
hold(distributionAxes(1),"On");
Plot.Long  = plot(distributionAxes(1), Grid.p, Long.logPosterior.p, "LineWidth",2, "Color",Color.Long, "DisplayName","ℙ(𝝑 | 𝙬)");
Plot.LongR = plot(distributionAxes(1), Grid.p, Rest.logPosterior.p, "LineWidth",2, "Color",Color.Rest, "LineStyle",'-', "DisplayName","ℙ(𝝑 | 𝙬͂)");

Plot.Prior = plot(distributionAxes(1), Grid.p, Prior.p,             "LineWidth",2, "Color",Color.Prior, "DisplayName","ℙ(𝝑)");
Plot.True  = xline(distributionAxes(1), GT.p, '--', "Color",Color.True, "LineWidth",3/2, "DisplayName","GT 𝝑");

ylabel(distributionAxes(1),{'Density';''},"Interpreter",'LaTeX');

 legend(distributionAxes(1), [Plot.Long,Plot.LongR,          Plot.Prior,Plot.True], "Location",'NorthEast', "Box",'Off', "AutoUpdate",'Off');

distributionAxes(1).XLim   = XLim;
distributionAxes(1).XTick  = linspace(distributionAxes(1).XLim(1), distributionAxes(1).XLim(2), 3);
distributionAxes(1).XTickLabel(floor(end/2)+1) = {"$\pi_{\sigma_{1}\to\sigma_{2}}$"};

distributionAxes(1).YTick = linspace(distributionAxes(1).YLim(1), distributionAxes(1).YLim(2), 3);

      distributionAxes(2) = nexttile(Tiles, [1 ceil(Showing/2)]); hold(distributionAxes(2),"On");
plot (distributionAxes(2), Grid.q, Long.logPosterior.q, "LineWidth",2, "Color",Color.Long);

plot (distributionAxes(2), Grid.q, Rest.logPosterior.q, "LineWidth",2, "Color",Color.Rest, "LineStyle",'--', "DisplayName","ℙ(𝝑 | 𝙬͂)");
plot (distributionAxes(2), Grid.q, Prior.q,             "LineWidth",2, "Color",Color.Prior);
xline(distributionAxes(2), GT.q, '--', "Color",Color.True, "LineWidth",3/2);

distributionAxes(2).XLim = XLim;
distributionAxes(2).XTick  = linspace(distributionAxes(2).XLim(1), distributionAxes(2).XLim(2), 3);
distributionAxes(2).XTickLabel(floor(end/2)+1) = {"$\pi_{\sigma_{2}\to\sigma_{1}}$"};

